import React, { useState } from "react";
import Axios from "axios";
import { useHistory } from "react-router";
import { Navbar } from "../Navbar";

const State = [
  { key: 1, value: "Andhra Pradesh" },
  { key: 2, value: "Arunachal Pradesh" },
  { key: 3, value: "Assam" },
  { key: 4, value: "Bihar" },
  { key: 5, value: "Chhattisgarh" },
  { key: 6, value: "Goa" },
  { key: 7, value: "Gujarat" },
  { key: 8, value: "Haryana" },
  { key: 9, value: "Himachal Pradesh" },
  { key: 10, value: "Jammu and Kashmir" },
  { key: 11, value: "Jharkhand" },
  { key: 12, value: "Karnataka" },
  { key: 13, value: "Kerala" },
  { key: 14, value: "Madhya Pradesh" },
  { key: 15, value: "Maharashtra" },
  { key: 16, value: "Manipur" },
  { key: 17, value: "Meghalaya" },
  { key: 18, value: "Mizoram" },
  { key: 19, value: "Nagaland" },
  { key: 20, value: "Odisha" },
  { key: 21, value: "Punjab" },
  { key: 22, value: "Rajasthan" },
  { key: 23, value: "Sikkim" },
  { key: 24, value: "Tamil Nadu" },
  { key: 25, value: "Telangana" },
  { key: 26, value: "Tripura" },
  { key: 27, value: "Uttar Pradesh" },
  { key: 28, value: "Uttarakhand" },
  { key: 29, value: "West Bengal" },
];
const Country = [
  { key: 1, value: "India" },
  { key: 2, value: "UAE" },
];
function ProfileUpload() {
  let history = useHistory();

  const [fname, setfname] = useState("");
  const [lname, setlname] = useState("");
  const [address, setaddress] = useState("");
  const [state, setstate] = useState(15);
  const [country, setcountry] = useState(1);
  const [city, setcity] = useState("");
  const [pincode, setpincode] = useState("");
  const [phone, setphone] = useState("");
  const fnamehandle = (event) => {
    setfname(event.currentTarget.value);
  };
  const lnamehandle = (event) => {
    setlname(event.currentTarget.value);
  };
  const addresshandle = (event) => {
    setaddress(event.currentTarget.value);
  };
  const cityhandle = (event) => {
    setcity(event.currentTarget.value);
  };
  const pincodehandle = (event) => {
    setpincode(event.currentTarget.value);
  };
  const phonehandle = (event) => {
    setphone(event.currentTarget.value);
  };
  const onchangestate = (event) => {
    setstate(event.currentTarget.value);
  };
  const onchangecountry = (event) => {
    setcountry(event.currentTarget.value);
  };

  const url = `http://localhost:5000/api/profile/addaddress`;
  const onsubmit = (e) => {
    const variables = {
      firstname: fname,
      lastname: lname,
      address: address,
      city: city,
      state:state,
      pincode: pincode,
      country:country,
      phone: phone,
    };
    e.preventDefault();
    Axios.post(url, variables).then((response) => {
      if (response.data.success) {
        alert("Product Uploaded Successfully");
        history.push("/category");
      } else {
        alert("Failed to Upload Product");
      }
    });
  };
  return (
    <div>
      <Navbar />
      <form className="ftco-section" onSubmit={onsubmit}
      method="post">
        <div className="containerr">
          <section id="main">
            <header class="page-header mb-30">
              <h1> New address</h1>
            </header>
          </section>
          <div className="row justify-content-center">
            <div className="col-md-12 col-lg-10">
              <div className="wrap ">
                <div className="p-4 p-lg-5">
                  <form className="signin-form">
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        First Name
                      </label>
                      <div class="col-md-10">
                        <input
                          class="form-control"
                          name="firstname"
                          type="text"
                          onChange={fnamehandle}
                          value={fname}
                        />
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        Last Name
                      </label>
                      <div class="col-md-10">
                        <input
                          class="form-control"
                          name="lastname"
                          type="text"
                          onChange={lnamehandle}
                          value={lname}
                        />
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        Address
                      </label>
                      <div class="col-md-10">
                        <input
                          class="form-control"
                          name="address"
                          type="text"
                          onChange={addresshandle}
                          value={address}
                        />
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        City
                      </label>
                      <div class="col-md-10">
                        <input
                          class="form-control"
                          name="city"
                          type="text"
                          onChange={cityhandle}
                          value={city}
                        />
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        State
                      </label>
                      <div class="col-md-10">
                        <select onChange={onchangestate} className="
                        form-control form-control-select my-3">
                          {State.map((item) => (
                            <option
                              className="my-1"
                              key={item.key}
                              value={item.key}
                            >
                              {item.value}
                            </option>
                          ))}
                        </select>
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        Pin Code
                      </label>
                      <div class="col-md-10">
                        <input
                          class="form-control"
                          name="pincode"
                          type="text"
                          onChange={pincodehandle}
                          value={pincode}
                        />
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        Country
                      </label>
                      <div class="col-md-10">
                        <select onChange={onchangecountry} className="form-control form-control-select my-3">
                          {Country.map((item) => (
                            <option
                              className="my-1"
                              key={item.key}
                              value={item.key}
                            >
                              {item.value}
                            </option>
                          ))}
                        </select>
                      </div>
                    </div>
                    <div className="form-group mb-3 d-flex flex-row align-items-center">
                      <label class="col-md-2 form-control-label d-flex justify-content-center">
                        Phone
                      </label>
                      <div class="col-md-10">
                        <input
                          class="form-control"
                          name="phone"
                          type="number"
                          onChange={phonehandle}
                          value={phone}
                        />
                      </div>
                    </div>
                    <div className="d-flex justify-content-end">
                      <button
                        type="submit"
                        className="btn btn-primary submit px-3"
                        style={{ width: "20%" }}
                        onClick={onsubmit}
                      >
                        Save
                      </button>
                    </div>
                  </form>
                </div>
              </div>
            </div>
          </div>
        </div>
      </form>
    </div>
  );
}

